// src/news-collection/telegram/getPostsInLast24Hours.ts
function loadChannelConfig() {
  try {
    return channels_default;
  } catch (error40) {
    console.error(
      "Error loading channels.json, falling back to SANA only:",
      error40
    );
    return { channels: [{ handle: "sana_gov", name: "" }] };
  }
}
async function getPostsInLast24Hours(specifiedDate) {
  console.log("Getting posts in last 24 hours...");
  const channels = loadChannelConfig();
  const latestEpoch = getEpochSecondsMostRecent_11_PM_InDamascus(specifiedDate);
  const latestDate = new Date(latestEpoch * 1e3);
  const earliestEpoch = latestEpoch - 60 * 60 * 24;
  const earliestDate = new Date(earliestEpoch * 1e3);
  const allPostsDictionary = await getPostsForAllChannels(
    channels.channels.map((channel) => channel.handle),
    earliestDate,
    latestDate
  );
  return allPostsDictionary;
}

// src/news-collection/browser.ts
async function fetchAndParseHTML(url2) {
  console.log(`Fetching ${url2}...`);
  const response = await axios_default.get(url2, {
    headers: {
      "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/91.0.4472.124 Safari/537.36"
    },
    timeout: 3e4
  });
  const parser = new DOMParser();
  const dom = parser.parseFromString(response.data, "text/html");
  console.log(`Successfully fetched and parsed ${url2}`);
  return dom;
}

// src/news-collection/extractSANAArticleContent.ts
async function extractSANAArticleContent(url2) {
  console.log(`\u{1F50D} Extracting article from ${url2.replace("https://", "")}`);
  try {
    const document2 = await fetchAndParseHTML(url2);
    const titleElement = document2.querySelector("h1.s-title");
    const title2 = titleElement?.textContent?.trim() || "";
    const paragraphElements = document2.querySelectorAll(
      ".entry-content.rbct p"
    );
    const paragraphs = Array.from(paragraphElements);
    const body = paragraphs.map((p2) => p2.textContent?.trim().replace(/\s+/g, " ") || "").filter((text2) => text2.length > 0).join("\n\n");
    return { title: title2, body };
  } catch (error40) {
    console.error(
      `Failed to extract from ${url2}, falling back to original content. Error:`,
      error40
    );
    return void 0;
  }
}

// src/news-collection/processSANATelegramPost.ts
async function processTelegramPost(message) {
  const articleUrl = message.match(
    /(?:https?:\/\/(?:www\.)?)?sana\.sy\/.*(?:\n|$)/gi
  );
  if (articleUrl) {
    const normalizedUrl = articleUrl[0].startsWith("https://") ? articleUrl[0] : `https://${articleUrl[0]}`;
    console.log(`\u{1F50D} Extracting article from ${articleUrl[0]}`);
    const articleContent = await extractSANAArticleContent(normalizedUrl);
    if (articleContent) {
      return `${articleContent.title}

${articleContent.body}

${normalizedUrl}`;
    }
  }
  let result = message.replace(/ــ{2,}[\n.]*/gm, "");
  result = result.replace(/#[^\s]+/g, "");
  result = result.replace(/\n\s*\n/g, "\n");
  return result;
}

// src/news-collection/collect.ts
async function collect(date5) {
  const postsDictionary = await getPostsInLast24Hours(
    date5
  );
  const sources = import_lodash.default.uniq(Object.keys(postsDictionary)).length;
  const posts = Object.values(postsDictionary).flat();
  console.log(`Found ${posts.length} posts from ${sources} unique sources`);
  console.log(`Processing posts...`);
  const processedPosts = await Promise.all(
    posts.map((post) => processTelegramPost(post))
  );
  return {
    newsItems: processedPosts,
    numberOfPosts: processedPosts.length,
    numberOfSources: sources
  };
}

