// src/formatting/measureTelegramRenderedHtml.ts
function safeFromCodePoint(cp2) {
  try {
    if (!Number.isFinite(cp2) || cp2 < 0 || cp2 > 1114111) return "\uFFFD";
    return String.fromCodePoint(cp2);
  } catch {
    return "\uFFFD";
  }
}
function decodeEntities(input) {
  return input.replace(
    /&#(\d+);/g,
    (_2, dec) => safeFromCodePoint(parseInt(dec, 10))
  ).replace(
    /&#x([0-9a-fA-F]+);/g,
    (_2, hex) => safeFromCodePoint(parseInt(hex, 16))
  ).replace(/&nbsp;/g, " ").replace(/&amp;/g, "&").replace(/&lt;/g, "<").replace(/&gt;/g, ">").replace(/&quot;/g, '"').replace(/&apos;/g, "'");
}
function measureTelegramRenderedHtml(html) {
  let s3 = html.replace(/<\/(p|div|h[1-6]|li|ul|ol|blockquote)>/gi, "\n").replace(/<br\s*\/?>/gi, "\n").replace(/<li[^>]*>/gi, "\u2022 ");
  s3 = s3.replace(/<[^>]+>/g, "");
  s3 = decodeEntities(s3);
  s3 = s3.replace(/\n{3,}/g, "\n\n");
  return { text: s3, length: s3.length };
}

